dfs(node, visited):
  visited.add(node)
  for neighbor in graph[node]:
    if neighbor not in visited:
      dfs(neighbor, visited)

bfs(start):
  queue = [start]
  visited = {start}
  while queue:
    node = queue.pop(0)
    for neighbor in graph[node]:
      if neighbor not in visited:
        visited.add(neighbor)
        queue.append(neighbor)

